export const gardenNoteRawContents: Record<string, string> = {
  "react-hooks-deep": "\n## Hooks 的本质\n\nHooks 不是魔法，它们是利用闭包和链表实现的普通 JavaScript 函数。\n\n### 关键 Hooks 深入\n\n#### useState\n- 触发重渲染的机制\n- 批量更新（batching）\n- 函数式更新的使用场景\n\n#### useEffect\n- 清理函数的重要性\n- 依赖数组的陷阱\n- 与生命周期的心智模型差异\n\n#### useRef\n- 不只是 DOM 引用\n- 保存可变值而不触发渲染\n- 与 useState 的选择\n\n### 自定义 Hooks 模式\n\n封装可复用的状态逻辑，保持组件简洁。\n",
  "react-state": "\n## React 状态管理的演进\n\n从最早的 `setState` 到现在的 Server Components，React 状态管理经历了巨大的变化。\n\n### 方案对比\n\n| 方案 | 适用场景 | 学习成本 |\n|------|---------|---------|\n| useState + useContext | 小型应用 | 低 |\n| Zustand | 中型应用 | 低 |\n| Jotai | 原子化状态 | 中 |\n| Redux Toolkit | 大型应用 | 高 |\n\n### 我的选择\n\n对于大多数项目，**Zustand** 是最佳平衡点——足够简单，又足够强大。\n\n### 核心原则\n\n1. 状态尽量靠近使用它的组件\n2. 避免过早抽象\n3. 派生状态优于冗余状态\n"
};

