export const journeyNodeRawContents: Record<string, string> = {
  "childhood": "\n## 童年记忆\n\n我的童年在南方一座小城度过。那时候最快乐的事，就是在周末跟着父母去新华书店，一待就是一下午。科普读物、百科全书、漫画杂志——什么都看，什么都好奇。\n\n家里第一台电脑是二年级时父亲买的。虽然那时候只会玩扫雷和纸牌，但那个会发光的屏幕就像一个通往另一个世界的窗口。从那以后，我对\"这个东西是怎么工作的\"产生了浓厚的兴趣。\n",
  "college": "\n## 大学四年的技术成长\n\n从大一第一次接触 C 语言的迷茫，到大四能够独立完成全栈项目的自信，这四年见证了一个程序员的诞生。\n\n### 学习路径\n\n1. **大一**：C 语言 → 数据结构 → 面向对象编程\n2. **大二**：算法竞赛训练 → Java/ Python → 数据库\n3. **大三**：Web 开发 → React 生态 → 操作系统/网络\n4. **大四**：实习经验 → 毕设项目 → 职业规划\n\n### 竞赛经历\n\nACM 集训队的训练是大学最难忘的经历之一。每周至少 3 次训练赛，刷了上千道题，从一个只能做水题的小白成长为能够独当一面的队员。\n",
  "first-job": "\n## 职场第一年\n\n从学生到工程师的身份转变，不仅是技术栈的扩展，更是思维方式的重塑。\n\n### 技术成长\n\n- React / Next.js 从会用 → 理解原理\n- TypeScript 从了解到必备\n- 从纯前端到全栈的跨越\n- 工程化思维的建立\n\n### 软技能\n\n- 跨部门沟通协作\n- 需求分析与技术方案设计\n- 时间管理与优先级排序\n",
  "high-school": "\n## 高中：奋斗与抉择\n\n高中是人生中第一个真正意义上的\"分水岭\"。进入重点高中后，身边的每一个同学都非常优秀，这种环境既是压力也是动力。\n\n最幸运的是遇到了信息学竞赛这个契机。在竞赛教练的指导下，我开始系统地学习算法和数据结构。那些挑灯夜战刷题的日子虽然辛苦，但每次 AC 一道难题时的成就感，足以抵消所有的疲惫。\n\n这段经历让我明白了两个道理：一是兴趣是最好的老师，二是系统性的刻意练习是提升能力的最有效途径。这两个认知一直陪伴我走到今天。\n",
  "life": "\n## 生活中的我\n\n工作只是人生的一部分。在代码之外，我努力让每一天都过得充实而有意义。\n\n### 阅读\n\n书籍是我最好的朋友。从技术书籍到人文社科，从科幻小说到哲学随笔——阅读让我看到更大的世界，也让我在忙碌的工作之余保持思考的习惯。\n\n> \"读一本好书，就是和许多高尚的人谈话。\" —— 歌德\n\n### 摄影\n\n摄影教会我观察。那些容易被忽略的光影、色彩、表情，在镜头下都变得珍贵。我不追求器材，只追求那一刻的感动。\n\n### 旅行\n\n世界很大，想去的地方很多。每一次旅行都是一次自我更新——在陌生的街头迷路，在不知名的咖啡馆发呆，在山顶等一场日出。这些经历让生活有了更多的层次和色彩。\n\n### 日常\n\n认真做一顿饭，整理一下房间，给朋友发一条消息——生活中的小确幸往往藏在最平凡的细节里。学会感受当下，是我一直在练习的事情。\n\n> 生活不在别处，就在此时此刻 ✨\n",
  "middle-school": "\n## 初中：探索与觉醒\n\n初中三年是人生中非常重要的转折期。从小学的被动学习，逐渐转变为主动探索。数学课上那些精妙的证明和推导让我着迷——原来世界上还有这样一种纯粹的美。\n\n信息技术课更是打开了新世界的大门。虽然当时学的 VB 在现在看来很\"古老\"，但那行 `MsgBox \"Hello, World!\"` 弹出的对话框，至今记忆犹新。那种\"我写了一段代码，电脑就按照我的想法行动了\"的体验，让我第一次感受到了编程的魅力。\n"
};

